  1	import * as React from 'react';
  2	
  3	import {
  4	  FormGroup,
  5	  TextInput,
  6	  Radio,
  7	  FormHelperText,
  8	  HelperText,
  9	  HelperTextItem,
 10	} from '@patternfly/react-core';
 11	import { LoadBalancing } from './types';
 12	import { useTranslation } from 'react-i18next';
 13	
 14	interface LoadBalancingProps {
 15	  loadBalancing: LoadBalancing;
 16	  onChange: (updated: LoadBalancing) => void;
 17	  formDisabled: boolean;
 18	}
 19	
 20	const LoadBalancingField: React.FC<LoadBalancingProps> = ({
 21	  loadBalancing,
 22	  onChange,
 23	  formDisabled,
 24	}) => {
 25	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 26	
 27	  return (
 28	    <>
 29	      <FormGroup
 30	        label={t('Load balancing Weight')}
 31	        isRequired
 32	        fieldId="weight"
 33	        className="pf-u-mb-md"
 34	      >
 35	        <TextInput
 36	          id="weight"
 37	          value={loadBalancing.weight}
 38	          onChange={(event) =>
 39	            onChange({
 40	              ...loadBalancing,
 41	              weight: Number(event.currentTarget.value),
 42	            })
 43	          }
 44	          isRequired
 45	          type="number"
 46	          placeholder="0"
 47	          isDisabled={formDisabled}
 48	        />
 49	        <FormHelperText>
 50	          <HelperText>
 51	            <HelperTextItem>
 52	              {t('Weight value to apply to weighted endpoints default: 120')}
 53	            </HelperTextItem>
 54	          </HelperText>
 55	        </FormHelperText>
 56	      </FormGroup>
 57	      <FormGroup label={t('Load balancing Geo')} isRequired fieldId="geo" className="pf-u-mb-md">
 58	        <TextInput
 59	          id="geo"
 60	          value={loadBalancing.geo}
 61	          onChange={(event) =>
 62	            onChange({
 63	              ...loadBalancing,
 64	              geo: String(event.currentTarget.value),
 65	            })
 66	          }
 67	          isRequired
 68	          placeholder={t("Geography Label (e.g. 'EU')")}
 69	          isDisabled={formDisabled}
 70	        />
 71	        <FormHelperText>
 72	          <HelperText>
 73	            <HelperTextItem>{t('Geo value to apply to geo endpoints')}</HelperTextItem>
 74	          </HelperText>
 75	        </FormHelperText>
 76	      </FormGroup>
 77	      <FormGroup
 78	        role="radiogroup"
 79	        hasNoPaddingTop
 80	        fieldId="default-geo"
 81	        label={t('Default Geo')}
 82	        isRequired
 83	        className="pf-u-mb-md"
 84	        aria-labelledby="issuer-label"
 85	      >
 86	        <div className="pf-u-display-flex pf-u-align-items-center">
 87	          <Radio
 88	            label={t('Enabled')}
 89	            isChecked={loadBalancing.defaultGeo === true}
 90	            onChange={() =>
 91	              onChange({
 92	                ...loadBalancing,
 93	                defaultGeo: true,
 94	              })
 95	            }
 96	            id="default-geo-enabled"
 97	            name="default-geo"
 98	            className="pf-u-mr-md"
 99	            isDisabled={formDisabled}
100	          />
101	          <Radio
102	            label={t('Disabled')}
103	            isChecked={loadBalancing.defaultGeo === false}
104	            onChange={() =>
105	              onChange({
106	                ...loadBalancing,
107	                defaultGeo: false,
108	              })
109	            }
110	            id="default-geo-disabled"
111	            name="default-geo"
112	            isDisabled={formDisabled}
113	          />
114	        </div>
115	        <FormHelperText>
116	          <HelperText>
117	            <HelperTextItem>{t('Geo value to apply to geo endpoints')}</HelperTextItem>
118	          </HelperText>
119	        </FormHelperText>
120	      </FormGroup>
121	    </>
122	  );
123	};
124	
125	export default LoadBalancingField;

